функција findContentChildren(g, s) {
  g.sort((a, b) => a - b); // Подредете ги факторите на алчноста на децата во растечки редослед
  s.sort((a, b) => a - b); // Подреди големини на колачиња во растечки редослед
  нека i = 0; // Покажувач за факторите на алчноста на децата
  нека j = 0; // Покажувач за големини на колачиња
  нека брои = 0; // Бројач за содржини деца
  додека (i < g.должина && j < s.должина) {
    ако (g[i] <= s[j]) { // Ако тековното колаче може да го задоволи тековното дете
      брои ++;
      јас++;
      j++;
    } else { // Ако тековното колаче не може да го задоволи тековното дете
      j++;
    }
  }
  брои за враќање;
}
```

